<?php
namespace app\Controllers\API; use app\Helpers\ApiResponse; use app\Services\AuthService; use app\Middleware\AuthMiddleware; use app\Repositories\UserRepository;
class AuthController{ private AuthService $service; public function __construct(){ $this->service=new AuthService(); } private function input():array{return json_decode(file_get_contents('php://input'),true)?:$_POST;} public function register(){ $r=$this->service->register($this->input()); $r['ok']?ApiResponse::success('Đăng ký thành công',$r['data'],201):ApiResponse::error('Dữ liệu không hợp lệ',$r['errors']??[],422);} public function login(){ $d=$this->input(); $r=$this->service->login($d['email']??'',$d['password']??''); $r['ok']?ApiResponse::success('Đăng nhập thành công',['user'=>$r['data'],'token'=>$r['data']['api_token']]):ApiResponse::error($r['message'],[],401);} public function logout(){ $u=AuthMiddleware::requireLogin(); (new UserRepository())->updateToken((int)$u['id'],null); ApiResponse::success('Đăng xuất thành công'); } public function profile(){ $u=AuthMiddleware::requireLogin(); unset($u['password'],$u['api_token']); ApiResponse::success('Thông tin cá nhân',$u); } public function updateProfile(){ $u=AuthMiddleware::requireLogin(); $r=$this->service->updateProfile((int)$u['id'],$this->input()); $r['ok']?ApiResponse::success('Cập nhật hồ sơ thành công',$r['data']):ApiResponse::error('Dữ liệu không hợp lệ',$r['errors']??[],422); } public function changePassword(){ $u=AuthMiddleware::requireLogin(); $d=$this->input(); $r=$this->service->changePassword((int)$u['id'],$d['old_password']??'',$d['new_password']??''); $r['ok']?ApiResponse::success('Đổi mật khẩu thành công'):ApiResponse::error($r['message'],[],422); }}
